final:
module RefModule (
    input wire clk,
    input wire clr,
    input wire pre,
    input wire D,
    output reg Q
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clr or posedge pre or posedge dbg_halt) begin
    if (clr)
        Q <= 1'b0;
    else if (pre)
        Q <= 1'b1;
    else
        Q <= D;
end

endmodule
